  ('judicial-f0899a01-moex-00100', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '監所管理人對受刑人之不服管教，出言恐嚇，造成受刑人心生害怕，其即以口頭向監所管理單位提出申訴， 後經監所審議小組調查後，認管理人無恐嚇之言行，監所依審議小組之認定，駁回受刑人之申訴，受刑人 應如何尋求救濟？', '["就監所之駁回決定，提起訴願程序", "就監所之駁回決定，提起復審程序", "就監所之駁回決定，提起行政訴訟", "就監所之駁回決定，提起復查程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00101', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政訴訟法規定，關於重新審理程序，下列敘述何者錯誤？', '["重新審理，原則上專屬為確定終局判決之原行政法院管轄", "重新審理之聲請，應於知悉確定判決之日起30日之不變期間內為之", "聲請重新審理不合法者，行政法院應以裁定駁回之", "原確定判決執行之效力，原則上因聲請重新審理而停止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00102', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '某市政府以甲未經許可設置廣告看板為由，限期命拆除之，甲為免被強制拆除造成損失而先自行拆除，之 後甲不服此拆除命令時，應如何請求救濟？', '["提起確認命拆除之處分無效之訴", "提起確認命拆除之處分違法之訴", "提起撤銷命拆除之處分訴訟", "提起一般給付之訴請求回復原狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00103', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '主管機關以甲為相對人作成授益處分，惟乙因該處分受有法律上不利益而向受理訴願機關提起訴願後，受 理訴願機關作成撤銷原處分之訴願決定。甲如欲提起行政訴訟，應以何者為被告？', '["原處分機關", "受理訴願機關", "以原處分機關及受理訴願機關為共同被告", "以原處分機關及受理訴願機關之共同上級機關為被告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
